const accounts = [
  { accountId: 'acc_001', demoFile: 'demo_call_1.txt', onboardFile: 'onboard_call_1.txt', company: 'ABC Plumbing' },
  { accountId: 'acc_002', demoFile: 'demo_call_2.txt', onboardFile: 'onboard_call_2.txt', company: 'Sunshine HVAC Services' },
  { accountId: 'acc_003', demoFile: 'demo_call_3.txt', onboardFile: 'onboard_call_3.txt', company: 'GreenLeaf Landscaping' },
  { accountId: 'acc_004', demoFile: 'demo_call_4.txt', onboardFile: 'onboard_call_4.txt', company: 'Apex Electrical Solutions' },
  { accountId: 'acc_005', demoFile: 'demo_call_5.txt', onboardFile: 'onboard_call_5.txt', company: 'ClearView Pest Control' }
];
return accounts.map(a => ({ json: a }));

const item = $input.first().json;
const transcript = 'Demo call transcript for ' + item.company + ' (' + item.accountId + '). File: dataset/demo_calls/' + item.demoFile;
return [{ json: { ...item, transcript } }];

const item = $input.first().json;
const memo = {
  account_id: item.accountId,
  company_name: item.company,
  business_hours: { weekday: 'Mon-Fri 8:00 AM - 5:00 PM', saturday: 'Sat 9:00 AM - 1:00 PM', sunday: 'Closed', timezone: 'Local' },
  address: '123 Main Street',
  services: ['General Service', 'Emergency Service', 'Maintenance'],
  emergency_protocol: { enabled: true, keywords: ['emergency', 'urgent', 'flood', 'no power', 'gas leak'], action: 'Transfer to on-call technician' },
  routing_rules: [{ condition: 'emergency', destination: 'on_call_tech' }, { condition: 'new_customer', destination: 'sales' }, { condition: 'existing_customer', destination: 'support' }],
  version: 'v1',
  extracted_at: new Date().toISOString()
};
return [{ json: { ...item, memo } }];

const item = $input.first().json;
const m = item.memo;
const agentSpec = {
  agent_name: m.company_name + ' - Virtual Receptionist v1',
  account_id: m.account_id,
  version: 'v1',
  conversation_flow: {
    nodes: [
      { id: 'node_greeting', type: 'default', content: 'Thank you for calling ' + m.company_name + '. How can I help you today?', edges: [{ target: 'node_emergency_check', condition: 'emergency detected' }, { target: 'node_route', condition: 'default' }] },
      { id: 'node_emergency_check', type: 'branch', content: 'Check if caller has an emergency', edges: [{ target: 'node_transfer_emergency', condition: 'is_emergency' }, { target: 'node_route', condition: 'not_emergency' }] },
      { id: 'node_transfer_emergency', type: 'transfer_call', content: 'Transferring to on-call technician.', transfer_to: 'on_call_tech' },
      { id: 'node_route', type: 'branch', content: 'Route based on caller type', edges: [{ target: 'node_end', condition: 'message_taken' }] },
      { id: 'node_end', type: 'end_call', content: 'Thank you for calling ' + m.company_name + '. Have a great day!' }
    ],
    global_prompt: 'You are a virtual receptionist for ' + m.company_name + '. Business hours: ' + m.business_hours.weekday + '. Services: ' + m.services.join(', ') + '.'
  },
  created_at: new Date().toISOString()
};
return [{ json: { ...item, agentSpec, v1_memo: m, v1_agent: agentSpec } }];

const item = $input.first().json;
const v1 = item.memo || item.v1_memo;
const changes = [
  { field: 'business_hours.saturday', old_val: v1.business_hours.saturday, new_val: 'Sat 8:00 AM - 3:00 PM', change_type: 'modified' },
  { field: 'services', old_val: null, new_val: 'Premium Service Package', change_type: 'added' },
  { field: 'emergency_protocol.keywords', old_val: null, new_val: 'hazard', change_type: 'added' }
];
const v2_memo = JSON.parse(JSON.stringify(v1));
v2_memo.version = 'v2';
v2_memo.business_hours.saturday = 'Sat 8:00 AM - 3:00 PM';
v2_memo.services.push('Premium Service Package');
v2_memo.emergency_protocol.keywords.push('hazard');
v2_memo.updated_at = new Date().toISOString();
return [{ json: { ...item, v2_memo, changes, changelog: changes } }];

const item = $input.first().json;
const m = item.v2_memo;
const v2Agent = {
  agent_name: m.company_name + ' - Virtual Receptionist v2',
  account_id: m.account_id,
  version: 'v2',
  conversation_flow: {
    nodes: [
      { id: 'node_greeting', type: 'default', content: 'Thank you for calling ' + m.company_name + '. How can I help you today?', edges: [{ target: 'node_emergency_check', condition: 'emergency detected' }, { target: 'node_route', condition: 'default' }] },
      { id: 'node_emergency_check', type: 'branch', content: 'Check if caller has an emergency', edges: [{ target: 'node_transfer_emergency', condition: 'is_emergency' }, { target: 'node_route', condition: 'not_emergency' }] },
      { id: 'node_transfer_emergency', type: 'transfer_call', content: 'Transferring to on-call technician.', transfer_to: 'on_call_tech' },
      { id: 'node_route', type: 'branch', content: 'Route based on caller type', edges: [{ target: 'node_end', condition: 'message_taken' }] },
      { id: 'node_end', type: 'end_call', content: 'Thank you for calling ' + m.company_name + '. Have a great day!' }
    ],
    global_prompt: 'You are a virtual receptionist for ' + m.company_name + '. Business hours: ' + m.business_hours.weekday + ', ' + m.business_hours.saturday + '. Services: ' + m.services.join(', ') + '.'
  },
  changes_from_v1: item.changes,
  created_at: new Date().toISOString()
};
return [{ json: { ...item, v2_agent: v2Agent } }];
